import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as o,o as r,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"افزودن WebDAV Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/webdav.md","filePath":"fa/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"fa/upload/webdav.md"};function c(p,e,h,u,b,m){return r(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="افزودن-webdav-channel" tabindex="-1">افزودن WebDAV Channel <a class="header-anchor" href="#افزودن-webdav-channel" aria-label="Permalink to &quot;افزودن WebDAV Channel&quot;">​</a></h1><h2 id="چه-زمانی-مناسب-است" tabindex="-1">چه زمانی مناسب است <a class="header-anchor" href="#چه-زمانی-مناسب-است" aria-label="Permalink to &quot;چه زمانی مناسب است&quot;">​</a></h2><p>WebDAV channel را زمانی استفاده کنید که:</p><ul><li>NAS، cloud drive یا object storage service دارید که WebDAV endpoint ارائه می‌دهد.</li><li>می‌خواهید uploaded images در WebDAV directory خودتان ذخیره شوند.</li><li>می‌خواهید credentials در جدول D1 <code>upload_channels</code> ذخیره شوند و طولانی‌مدت در frontend exposed نباشند.</li></ul><h2 id="پیش-از-شروع-چه-چیزهایی-لازم-است" tabindex="-1">پیش از شروع چه چیزهایی لازم است <a class="header-anchor" href="#پیش-از-شروع-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;پیش از شروع چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>کاربرد</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>URL سمت سرور WebDAV، مثل <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>برای sign in به WebDAV service.</td></tr><tr><td>Password</td><td>برای sign in به WebDAV service.</td></tr><tr><td>Authentication mode</td><td>پیش‌فرض <code>Basic</code> است. فقط اگر server نیاز داشت از <code>Digest</code> یا auto negotiation استفاده کنید.</td></tr><tr><td>Storage directory</td><td>directory ذخیره files. پیش‌فرض <code>imgbed</code>.</td></tr></tbody></table><h2 id="کجا-اضافه-کنیم" tabindex="-1">کجا اضافه کنیم <a class="header-anchor" href="#کجا-اضافه-کنیم" aria-label="Permalink to &quot;کجا اضافه کنیم&quot;">​</a></h2><ol><li>System Settings را باز کنید.</li><li>وارد Upload Settings شوید.</li><li>از گوشه بالا سمت راست Add Channel را بزنید.</li><li><code>WebDAV</code> را انتخاب کنید.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کاربرد</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>نام قابل‌تشخیص برای WebDAV channel، مثل <code>koofr</code> یا <code>nas</code>.</td><td>Yes</td></tr><tr><td>Endpoint</td><td>endpoint کامل WebDAV همراه <code>https://</code>.</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username.</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password.</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>معمولاً <code>Basic</code>; اگر server digest authentication می‌خواهد از <code>Digest</code> استفاده کنید.</td><td>Yes</td></tr><tr><td>Storage directory</td><td>محل ذخیره files. پیش‌فرض <code>imgbed</code>.</td><td>No</td></tr></tbody></table><h2 id="مثال-fie-nl-tab-digital" tabindex="-1">مثال: fie.nl.tab.digital <a class="header-anchor" href="#مثال-fie-nl-tab-digital" aria-label="Permalink to &quot;مثال: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-ساخت-app-password" tabindex="-1">1. ساخت App Password <a class="header-anchor" href="#_1-ساخت-app-password" aria-label="Permalink to &quot;1. ساخت App Password&quot;">​</a></h3><p>account security settings را باز کنید، application passwords را پیدا کنید و یک app password جدید بسازید.</p><p><img src="'+t+'" alt="Create an app password" loading="lazy"></p><p>پس از ساخت، app password جدید را copy و ذخیره کنید. معمولاً فقط یک‌بار نمایش داده می‌شود.</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-پر-کردن-webdav-configuration-در-imgbed" tabindex="-1">2. پر کردن WebDAV Configuration در ImgBed <a class="header-anchor" href="#_2-پر-کردن-webdav-configuration-در-imgbed" aria-label="Permalink to &quot;2. پر کردن WebDAV Configuration در ImgBed&quot;">​</a></h3><p>به ImgBed برگردید و WebDAV channel اضافه کنید:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV URL ارائه‌شده توسط <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Username</td><td>WebDAV username شما.</td></tr><tr><td>Password</td><td>app password که تازه ساخته‌اید.</td></tr><tr><td>Authentication mode</td><td>در بیشتر موارد با <code>Basic</code> شروع کنید.</td></tr><tr><td>Storage directory</td><td>پیش‌فرض <code>imgbed</code> است؛ می‌توانید directory دلخواه هم بدهید.</td></tr></tbody></table><p><img src="'+d+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="رفتار-upload-برای-فایل‌های-بزرگ" tabindex="-1">رفتار Upload برای فایل‌های بزرگ <a class="header-anchor" href="#رفتار-upload-برای-فایل‌های-بزرگ" aria-label="Permalink to &quot;رفتار Upload برای فایل‌های بزرگ&quot;">​</a></h2><p>WebDAV channel اکنون از real session-based chunked upload استفاده می‌کند.</p><p>files کوچک به‌صورت یک complete file upload می‌شوند. files بزرگ‌تر از 64 MiB به‌صورت خودکار به chunkهای حدود 10 MiB تقسیم می‌شوند و داخل remote chunk directory upload می‌شوند.</p><p>WebDAV service لازم نیست <code>partial update</code> یا offset-based writes را پشتیبانی کند. ImgBed chunks را روی remote server به یک file بزرگ merge نمی‌کند. به‌جای آن chunk manifest ذخیره می‌شود و هنگام request، chunks به‌ترتیب خوانده می‌شوند.</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB یا کمتر</td><td>Normal upload</td><td>یک complete file</td></tr><tr><td>بیشتر از 64 MiB</td><td>Real session chunked upload</td><td>یک chunk directory شامل چند chunk file</td></tr></tbody></table><p>chunk directory فقط روی remote storage layout اثر دارد. URL فایل در ImgBed تغییر نمی‌کند. کاربران همچنان از link اصلی <code>/file/...</code> به file دسترسی دارند.</p><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><ol><li>Upload Settings را باز کنید.</li><li>Add Channel را بزنید.</li><li><code>WebDAV</code> را انتخاب کنید.</li><li>channel name قابل‌تشخیص وارد کنید، مثل <code>koofr</code>.</li><li>WebDAV endpoint را وارد کنید، مثل <code>https://app.koofr.net/dav/Koofr</code>.</li><li>username و password را وارد کنید.</li><li>authentication mode را به‌صورت پیش‌فرض <code>Basic</code> نگه دارید.</li><li>storage directory را <code>imgbed</code> نگه دارید یا directory خودتان را وارد کنید.</li><li>Save را بزنید.</li><li>بعد از save، channel card را بررسی کنید، اگر capacity query در دسترس است اجرا کنید، و یک test file upload کنید.</li></ol><h2 id="روش-بررسی" tabindex="-1">روش بررسی <a class="header-anchor" href="#روش-بررسی" aria-label="Permalink to &quot;روش بررسی&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>روش بررسی</th></tr></thead><tbody><tr><td>Channel card appears</td><td>پس از Save، WebDAV channel card باید در Upload Settings دیده شود.</td></tr><tr><td>Channel is enabled</td><td>switch بالای card باید روشن بماند.</td></tr><tr><td>Credentials are saved</td><td>detail view باید Endpoint، username، authentication mode و storage directory را نشان دهد.</td></tr><tr><td>Small file upload works</td><td>یک test image upload کنید و ببینید file در WebDAV directory ظاهر شده است.</td></tr><tr><td>Large file rule works</td><td>files بزرگ‌تر از 64 MiB از chunked upload استفاده می‌کنند و remote chunk directory می‌سازند.</td></tr><tr><td>Capacity query works</td><td>اگر server capacity information را پشتیبانی کند، query مقدار used و total capacity را نشان می‌دهد.</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="چرا-webdav-files-بزرگ-chunk-directory-می‌سازند؟" tabindex="-1">چرا WebDAV files بزرگ chunk directory می‌سازند؟ <a class="header-anchor" href="#چرا-webdav-files-بزرگ-chunk-directory-می‌سازند؟" aria-label="Permalink to &quot;چرا WebDAV files بزرگ chunk directory می‌سازند؟&quot;">​</a></h3><p>این روش فعلی storage برای files بزرگ است.</p><p>files بزرگ‌تر از 64 MiB در remote side به یک file بزرگ merge نمی‌شوند. به‌صورت chunk directory ذخیره می‌شوند. ImgBed chunk manifest را record می‌کند و content کامل را با خواندن chunks به‌ترتیب برمی‌گرداند.</p><h3 id="اگر-large-file-upload-fail-شد،-اول-چه-چیزهایی-را-بررسی-کنم؟" tabindex="-1">اگر large file upload fail شد، اول چه چیزهایی را بررسی کنم؟ <a class="header-anchor" href="#اگر-large-file-upload-fail-شد،-اول-چه-چیزهایی-را-بررسی-کنم؟" aria-label="Permalink to &quot;اگر large file upload fail شد، اول چه چیزهایی را بررسی کنم؟&quot;">​</a></h3><p>اول Endpoint، username، password و storage directory را بررسی کنید. سپس مطمئن شوید WebDAV service اجازه directory creation، file writing و file reading می‌دهد.</p><p>اگر capacity query fail شد اما small file upload کار کرد، ممکن است server capacity reporting را پشتیبانی نکند یا محدود کرده باشد. این لزوماً یعنی upload unavailable نیست.</p><h3 id="کدام-authentication-mode-را-استفاده-کنم؟" tabindex="-1">کدام authentication mode را استفاده کنم؟ <a class="header-anchor" href="#کدام-authentication-mode-را-استفاده-کنم؟" aria-label="Permalink to &quot;کدام authentication mode را استفاده کنم؟&quot;">​</a></h3><p>با <code>Basic</code> شروع کنید.</p><p>اگر server صریحاً digest authentication می‌خواهد، <code>Digest</code> را انتخاب کنید.</p><p>اگر مطمئن نیستید، automatic negotiation را استفاده کنید.</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV endpoint, username و password را آماده کنید</span></span>
<span class="line"><span>-&gt; Upload Settings را باز کنید</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; WebDAV را انتخاب کنید</span></span>
<span class="line"><span>-&gt; Endpoint / username / password را وارد کنید</span></span>
<span class="line"><span>-&gt; authentication mode را پیش‌فرض Basic نگه دارید</span></span>
<span class="line"><span>-&gt; storage directory را پیش‌فرض imgbed نگه دارید</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; capacity query</span></span>
<span class="line"><span>-&gt; test file upload</span></span></code></pre></div>`,44)])])}const y=o(s,[["render",c]]);export{k as __pageData,y as default};
